You are implementing a shipment tracking Blazor Web App. The project is already scaffolded at `/tmp/sv-2df1591ac2884398990cb75fd56ca663/ShipmentTracker/` with Interactive Auto Global mode and Individual auth.

**Project structure:**
- `ShipmentTracker/` - server project (hosts app, EF Core, APIs)
- `ShipmentTracker.Client/` - client project (interactive UI components)

**Requirements:**
1. Dispatchers view a list of shipments with status and destination
2. Customers check their shipment status and estimated delivery
3. Interactive Auto Global mode (already configured)
4. Individual accounts auth (already configured)

**What to implement:**

### 1. Shipment Model (server project)
Create `ShipmentTracker/Data/Shipment.cs`:
```csharp
using System.ComponentModel.DataAnnotations;

namespace ShipmentTracker.Data;

public class Shipment
{
    public int Id { get; set; }

    [Required]
    public string TrackingNumber { get; set; } = string.Empty;

    [Required]
    public string Origin { get; set; } = string.Empty;

    [Required]
    public string Destination { get; set; } = string.Empty;

    public ShipmentStatus Status { get; set; } = ShipmentStatus.Pending;

    public DateTime CreatedDate { get; set; } = DateTime.UtcNow;

    public DateTime? EstimatedDelivery { get; set; }

    public string? CustomerEmail { get; set; }

    public string? DispatcherId { get; set; }
}

public enum ShipmentStatus
{
    Pending,
    PickedUp,
    InTransit,
    OutForDelivery,
    Delivered,
    Cancelled
}
```

### 2. Shared DTO (Client project)
Create `ShipmentTracker.Client/Models/ShipmentDto.cs`:
```csharp
namespace ShipmentTracker.Client.Models;

public class ShipmentDto
{
    public int Id { get; set; }
    public string TrackingNumber { get; set; } = string.Empty;
    public string Origin { get; set; } = string.Empty;
    public string Destination { get; set; } = string.Empty;
    public string Status { get; set; } = string.Empty;
    public DateTime CreatedDate { get; set; }
    public DateTime? EstimatedDelivery { get; set; }
    public string? CustomerEmail { get; set; }
}
```

### 3. Service Interface (Client project)
Create `ShipmentTracker.Client/Services/IShipmentService.cs`:
```csharp
using ShipmentTracker.Client.Models;

namespace ShipmentTracker.Client.Services;

public interface IShipmentService
{
    Task<List<ShipmentDto>> GetAllShipmentsAsync();
    Task<ShipmentDto?> GetShipmentByTrackingNumberAsync(string trackingNumber);
    Task<ShipmentDto> CreateShipmentAsync(ShipmentDto shipment);
    Task<ShipmentDto> UpdateShipmentStatusAsync(int id, string status);
}
```

### 4. Client-side HTTP implementation (Client project)
Create `ShipmentTracker.Client/Services/ShipmentHttpService.cs`:
```csharp
using System.Net.Http.Json;
using ShipmentTracker.Client.Models;

namespace ShipmentTracker.Client.Services;

public class ShipmentHttpService : IShipmentService
{
    private readonly HttpClient _http;

    public ShipmentHttpService(HttpClient http)
    {
        _http = http;
    }

    public async Task<List<ShipmentDto>> GetAllShipmentsAsync()
    {
        return await _http.GetFromJsonAsync<List<ShipmentDto>>("api/shipments") ?? new();
    }

    public async Task<ShipmentDto?> GetShipmentByTrackingNumberAsync(string trackingNumber)
    {
        var response = await _http.GetAsync($"api/shipments/track/{trackingNumber}");
        if (response.IsSuccessStatusCode)
            return await response.Content.ReadFromJsonAsync<ShipmentDto>();
        return null;
    }

    public async Task<ShipmentDto> CreateShipmentAsync(ShipmentDto shipment)
    {
        var response = await _http.PostAsJsonAsync("api/shipments", shipment);
        response.EnsureSuccessStatusCode();
        return await response.Content.ReadFromJsonAsync<ShipmentDto>() ?? shipment;
    }

    public async Task<ShipmentDto> UpdateShipmentStatusAsync(int id, string status)
    {
        var response = await _http.PutAsJsonAsync($"api/shipments/{id}/status", new { Status = status });
        response.EnsureSuccessStatusCode();
        return await response.Content.ReadFromJsonAsync<ShipmentDto>() ?? new();
    }
}
```

### 5. Server-side direct implementation (Server project)
Create `ShipmentTracker/Services/ShipmentServerService.cs`:
```csharp
using Microsoft.EntityFrameworkCore;
using ShipmentTracker.Client.Models;
using ShipmentTracker.Client.Services;
using ShipmentTracker.Data;

namespace ShipmentTracker.Services;

public class ShipmentServerService : IShipmentService
{
    private readonly ApplicationDbContext _db;

    public ShipmentServerService(ApplicationDbContext db)
    {
        _db = db;
    }

    public async Task<List<ShipmentDto>> GetAllShipmentsAsync()
    {
        return await _db.Shipments
            .OrderByDescending(s => s.CreatedDate)
            .Select(s => MapToDto(s))
            .ToListAsync();
    }

    public async Task<ShipmentDto?> GetShipmentByTrackingNumberAsync(string trackingNumber)
    {
        var shipment = await _db.Shipments
            .FirstOrDefaultAsync(s => s.TrackingNumber == trackingNumber);
        return shipment is null ? null : MapToDto(shipment);
    }

    public async Task<ShipmentDto> CreateShipmentAsync(ShipmentDto dto)
    {
        var shipment = new Shipment
        {
            TrackingNumber = dto.TrackingNumber,
            Origin = dto.Origin,
            Destination = dto.Destination,
            Status = Enum.Parse<ShipmentStatus>(dto.Status, true),
            CustomerEmail = dto.CustomerEmail,
            EstimatedDelivery = dto.EstimatedDelivery,
            CreatedDate = DateTime.UtcNow
        };
        _db.Shipments.Add(shipment);
        await _db.SaveChangesAsync();
        return MapToDto(shipment);
    }

    public async Task<ShipmentDto> UpdateShipmentStatusAsync(int id, string status)
    {
        var shipment = await _db.Shipments.FindAsync(id)
            ?? throw new InvalidOperationException("Shipment not found");
        shipment.Status = Enum.Parse<ShipmentStatus>(status, true);
        await _db.SaveChangesAsync();
        return MapToDto(shipment);
    }

    private static ShipmentDto MapToDto(Shipment s) => new()
    {
        Id = s.Id,
        TrackingNumber = s.TrackingNumber,
        Origin = s.Origin,
        Destination = s.Destination,
        Status = s.Status.ToString(),
        CreatedDate = s.CreatedDate,
        EstimatedDelivery = s.EstimatedDelivery,
        CustomerEmail = s.CustomerEmail
    };
}
```

### 6. Update ApplicationDbContext
Edit `ShipmentTracker/Data/ApplicationDbContext.cs` to add:
```csharp
public DbSet<Shipment> Shipments => Set<Shipment>();
```

### 7. API Endpoints (Server project)
Create `ShipmentTracker/Endpoints/ShipmentEndpoints.cs`:
```csharp
using Microsoft.EntityFrameworkCore;
using ShipmentTracker.Client.Models;
using ShipmentTracker.Data;

namespace ShipmentTracker.Endpoints;

public static class ShipmentEndpoints
{
    public static void MapShipmentEndpoints(this WebApplication app)
    {
        var group = app.MapGroup("api/shipments");

        group.MapGet("/", async (ApplicationDbContext db) =>
        {
            var shipments = await db.Shipments
                .OrderByDescending(s => s.CreatedDate)
                .Select(s => new ShipmentDto
                {
                    Id = s.Id,
                    TrackingNumber = s.TrackingNumber,
                    Origin = s.Origin,
                    Destination = s.Destination,
                    Status = s.Status.ToString(),
                    CreatedDate = s.CreatedDate,
                    EstimatedDelivery = s.EstimatedDelivery,
                    CustomerEmail = s.CustomerEmail
                })
                .ToListAsync();
            return Results.Ok(shipments);
        }).RequireAuthorization();

        group.MapGet("/track/{trackingNumber}", async (string trackingNumber, ApplicationDbContext db) =>
        {
            var shipment = await db.Shipments
                .FirstOrDefaultAsync(s => s.TrackingNumber == trackingNumber);
            if (shipment is null) return Results.NotFound();
            return Results.Ok(new ShipmentDto
            {
                Id = shipment.Id,
                TrackingNumber = shipment.TrackingNumber,
                Origin = shipment.Origin,
                Destination = shipment.Destination,
                Status = shipment.Status.ToString(),
                CreatedDate = shipment.CreatedDate,
                EstimatedDelivery = shipment.EstimatedDelivery,
                CustomerEmail = shipment.CustomerEmail
            });
        }).RequireAuthorization();

        group.MapPost("/", async (ShipmentDto dto, ApplicationDbContext db) =>
        {
            var shipment = new Shipment
            {
                TrackingNumber = dto.TrackingNumber,
                Origin = dto.Origin,
                Destination = dto.Destination,
                Status = Enum.Parse<ShipmentStatus>(dto.Status, true),
                CustomerEmail = dto.CustomerEmail,
                EstimatedDelivery = dto.EstimatedDelivery,
                CreatedDate = DateTime.UtcNow
            };
            db.Shipments.Add(shipment);
            await db.SaveChangesAsync();
            return Results.Created($"api/shipments/{shipment.Id}", new ShipmentDto
            {
                Id = shipment.Id,
                TrackingNumber = shipment.TrackingNumber,
                Origin = shipment.Origin,
                Destination = shipment.Destination,
                Status = shipment.Status.ToString(),
                CreatedDate = shipment.CreatedDate,
                EstimatedDelivery = shipment.EstimatedDelivery,
                CustomerEmail = shipment.CustomerEmail
            });
        }).RequireAuthorization();

        group.MapPut("/{id}/status", async (int id, StatusUpdateRequest request, ApplicationDbContext db) =>
        {
            var shipment = await db.Shipments.FindAsync(id);
            if (shipment is null) return Results.NotFound();
            shipment.Status = Enum.Parse<ShipmentStatus>(request.Status, true);
            await db.SaveChangesAsync();
            return Results.Ok(new ShipmentDto
            {
                Id = shipment.Id,
                TrackingNumber = shipment.TrackingNumber,
                Origin = shipment.Origin,
                Destination = shipment.Destination,
                Status = shipment.Status.ToString(),
                CreatedDate = shipment.CreatedDate,
                EstimatedDelivery = shipment.EstimatedDelivery,
                CustomerEmail = shipment.CustomerEmail
            });
        }).RequireAuthorization();
    }
}

public record StatusUpdateRequest(string Status);
```

