@page "/shipments"
@using ShipmentTracker.Client.Models
@using ShipmentTracker.Client.Services
@attribute [Microsoft.AspNetCore.Authorization.Authorize]
@inject IShipmentService ShipmentService

<PageTitle>Dispatcher Dashboard</PageTitle>

<h1>Shipments</h1>

<div class="row mb-3">
    <div class="col-md-4">
        <input type="text" class="form-control" placeholder="Filter by destination..." @bind="filterText" @bind:event="oninput" />
    </div>
    <div class="col-md-4">
        <select class="form-select" @bind="statusFilter">
            <option value="">All Statuses</option>
            <option value="Pending">Pending</option>
            <option value="PickedUp">Picked Up</option>
            <option value="InTransit">In Transit</option>
            <option value="OutForDelivery">Out for Delivery</option>
            <option value="Delivered">Delivered</option>
            <option value="Cancelled">Cancelled</option>
        </select>
    </div>
    <div class="col-md-4 text-end">
        <button class="btn btn-success" @onclick="ShowCreateForm">+ New Shipment</button>
    </div>
</div>

@if (showCreateForm)
{
    <div class="card mb-3">
        <div class="card-body">
            <h5>Create New Shipment</h5>
            <div class="row g-2">
                <div class="col-md-3">
                    <input type="text" class="form-control" placeholder="Origin" @bind="newShipment.Origin" />
                </div>
                <div class="col-md-3">
                    <input type="text" class="form-control" placeholder="Destination" @bind="newShipment.Destination" />
                </div>
                <div class="col-md-3">
                    <input type="email" class="form-control" placeholder="Customer Email" @bind="newShipment.CustomerEmail" />
                </div>
                <div class="col-md-3">
                    <input type="date" class="form-control" @bind="estimatedDeliveryDate" />
                </div>
            </div>
            <div class="mt-2">
                <button class="btn btn-primary" @onclick="CreateShipment">Create</button>
                <button class="btn btn-secondary ms-2" @onclick="() => showCreateForm = false">Cancel</button>
            </div>
            @if (!string.IsNullOrEmpty(createError))
            {
                <div class="alert alert-danger mt-2">@createError</div>
            }
        </div>
    </div>
}

@if (shipments is null)
{
    <p><em>Loading shipments...</em></p>
}
else if (!FilteredShipments.Any())
{
    <p>No shipments found.</p>
}
else
{
    <table class="table table-striped table-hover">
        <thead>
            <tr>
                <th>Tracking #</th>
                <th>Origin</th>
                <th>Destination</th>
                <th>Status</th>
                <th>Created</th>
                <th>Est. Delivery</th>
                <th>Actions</th>
            </tr>
        </thead>
        <tbody>
            @foreach (var shipment in FilteredShipments)
            {
                <tr>
                    <td><code>@shipment.TrackingNumber</code></td>
                    <td>@shipment.Origin</td>
                    <td>@shipment.Destination</td>
                    <td><span class="badge @GetStatusBadgeClass(shipment.Status)">@FormatStatus(shipment.Status)</span></td>
                    <td>@shipment.CreatedDate.ToString("yyyy-MM-dd")</td>
                    <td>@(shipment.EstimatedDelivery?.ToString("yyyy-MM-dd") ?? "—")</td>
                    <td>
                        <select class="form-select form-select-sm" style="width: auto; display: inline-block;"
                                value="@shipment.Status"
                                @onchange="(e) => UpdateStatus(shipment, e.Value?.ToString() ?? shipment.Status)">
                            <option value="Pending">Pending</option>
                            <option value="PickedUp">Picked Up</option>
                            <option value="InTransit">In Transit</option>
                            <option value="OutForDelivery">Out for Delivery</option>
                            <option value="Delivered">Delivered</option>
                            <option value="Cancelled">Cancelled</option>
                        </select>
                    </td>
                </tr>
            }
        </tbody>
    </table>
}

@code {
    private List<ShipmentDto>? shipments;
    private string filterText = string.Empty;
    private string statusFilter = string.Empty;
    private bool showCreateForm;
    private ShipmentDto newShipment = new();
    private DateTime? estimatedDeliveryDate;
    private string? createError;

    private IEnumerable<ShipmentDto> FilteredShipments =>
        (shipments ?? new()).Where(s =>
            (string.IsNullOrEmpty(filterText) || s.Destination.Contains(filterText, StringComparison.OrdinalIgnoreCase)) &&
            (string.IsNullOrEmpty(statusFilter) || s.Status == statusFilter));

    protected override async Task OnInitializedAsync()
    {
        shipments = await ShipmentService.GetAllShipmentsAsync();
    }

    private void ShowCreateForm()
    {
        showCreateForm = true;
        newShipment = new ShipmentDto();
        estimatedDeliveryDate = null;
        createError = null;
    }

    private async Task CreateShipment()
    {
        if (string.IsNullOrWhiteSpace(newShipment.Origin) || string.IsNullOrWhiteSpace(newShipment.Destination))
        {
            createError = "Origin and Destination are required.";
            return;
        }

        newShipment.TrackingNumber = $"TRK-{Guid.NewGuid().ToString()[..8].ToUpper()}";
        newShipment.Status = "Pending";
        newShipment.EstimatedDelivery = estimatedDeliveryDate;

        var created = await ShipmentService.CreateShipmentAsync(newShipment);
        shipments?.Insert(0, created);
        showCreateForm = false;
        createError = null;
    }

    private async Task UpdateStatus(ShipmentDto shipment, string newStatus)
    {
        var updated = await ShipmentService.UpdateShipmentStatusAsync(shipment.Id, newStatus);
        shipment.Status = updated.Status;
    }

    private static string GetStatusBadgeClass(string status) => status switch
    {
        "Pending" => "bg-secondary",
        "PickedUp" => "bg-info",
        "InTransit" => "bg-primary",
        "OutForDelivery" => "bg-warning text-dark",
        "Delivered" => "bg-success",
        "Cancelled" => "bg-danger",
        _ => "bg-secondary"
    };

    private static string FormatStatus(string status) => status switch
    {
        "PickedUp" => "Picked Up",
        "InTransit" => "In Transit",
        "OutForDelivery" => "Out for Delivery",
        _ => status
    };
}

@page "/track"
@using ShipmentTracker.Client.Models
@using ShipmentTracker.Client.Services
@attribute [Microsoft.AspNetCore.Authorization.Authorize]
@inject IShipmentService ShipmentService

<PageTitle>Track Shipment</PageTitle>

<h1>Track Your Shipment</h1>

<div class="row mb-4">
    <div class="col-md-6">
        <div class="input-group">
            <input type="text" class="form-control" placeholder="Enter tracking number (e.g., TRK-A1B2C3D4)"
                   @bind="trackingNumber" @onkeydown="HandleKeyDown" />
            <button class="btn btn-primary" @onclick="SearchShipment" disabled="@isSearching">
                @if (isSearching)
                {
                    <span class="spinner-border spinner-border-sm me-1"></span>
                }
                Track
            </button>
        </div>
    </div>
</div>

@if (searchPerformed && shipment is null)
{
    <div class="alert alert-warning">
        <strong>Not found.</strong> No shipment matches tracking number "<code>@searchedNumber</code>". Please verify and try again.
    </div>
}

@if (shipment is not null)
{
    <div class="card">
        <div class="card-header">
            <h5 class="mb-0">Shipment <code>@shipment.TrackingNumber</code></h5>
        </div>
        <div class="card-body">
            <div class="row">
                <div class="col-md-6">
                    <dl>
                        <dt>Origin</dt>
                        <dd>@shipment.Origin</dd>
                        <dt>Destination</dt>
                        <dd>@shipment.Destination</dd>
                        <dt>Status</dt>
                        <dd><span class="badge @GetStatusBadgeClass(shipment.Status) fs-6">@FormatStatus(shipment.Status)</span></dd>
                    </dl>
                </div>
                <div class="col-md-6">
                    <dl>
                        <dt>Shipped Date</dt>
                        <dd>@shipment.CreatedDate.ToString("MMMM dd, yyyy")</dd>
                        <dt>Estimated Delivery</dt>
                        <dd>
                            @if (shipment.EstimatedDelivery.HasValue)
                            {
                                <strong>@shipment.EstimatedDelivery.Value.ToString("MMMM dd, yyyy")</strong>
                            }
                            else
                            {
                                <span class="text-muted">Not yet determined</span>
                            }
                        </dd>
                    </dl>
                </div>
            </div>

            <h6 class="mt-3">Delivery Progress</h6>
            <div class="progress" style="height: 25px;">
                <div class="progress-bar @GetProgressBarClass(shipment.Status)"
                     role="progressbar"
                     style="width: @GetProgressPercent(shipment.Status)%"
                     aria-valuenow="@GetProgressPercent(shipment.Status)"
                     aria-valuemin="0" aria-valuemax="100">
                    @FormatStatus(shipment.Status)
                </div>
            </div>
        </div>
    </div>
}

@code {
    private string trackingNumber = string.Empty;
    private string searchedNumber = string.Empty;
    private ShipmentDto? shipment;
    private bool searchPerformed;
    private bool isSearching;

    private async Task SearchShipment()
    {
        if (string.IsNullOrWhiteSpace(trackingNumber)) return;

        isSearching = true;
        searchedNumber = trackingNumber.Trim();
        shipment = await ShipmentService.GetShipmentByTrackingNumberAsync(searchedNumber);
        searchPerformed = true;
        isSearching = false;
    }

    private async Task HandleKeyDown(Microsoft.AspNetCore.Components.Web.KeyboardEventArgs e)
    {
        if (e.Key == "Enter")
            await SearchShipment();
    }

    private static string GetStatusBadgeClass(string status) => status switch
    {
        "Pending" => "bg-secondary",
        "PickedUp" => "bg-info",
        "InTransit" => "bg-primary",
        "OutForDelivery" => "bg-warning text-dark",
        "Delivered" => "bg-success",
        "Cancelled" => "bg-danger",
        _ => "bg-secondary"
    };

    private static string FormatStatus(string status) => status switch
    {
        "PickedUp" => "Picked Up",
        "InTransit" => "In Transit",
        "OutForDelivery" => "Out for Delivery",
        _ => status
    };

    private static string GetProgressBarClass(string status) => status switch
    {
        "Cancelled" => "bg-danger",
        "Delivered" => "bg-success",
        _ => "bg-primary"
    };

    private static int GetProgressPercent(string status) => status switch
    {
        "Pending" => 10,
        "PickedUp" => 30,
        "InTransit" => 55,
        "OutForDelivery" => 80,
        "Delivered" => 100,
        "Cancelled" => 100,
        _ => 0
    };
}

