        if (string.IsNullOrWhiteSpace(trackingNumber)) return;

        isSearching = true;
        searchedNumber = trackingNumber.Trim();
        shipment = await ShipmentService.GetShipmentByTrackingNumberAsync(searchedNumber);
        searchPerformed = true;
        isSearching = false;
    }

    private async Task HandleKeyDown(Microsoft.AspNetCore.Components.Web.KeyboardEventArgs e)
    {
        if (e.Key == "Enter")
            await SearchShipment();
    }

    private static string GetStatusBadgeClass(string status) => status switch
    {
        "Pending" => "bg-secondary",
        "PickedUp" => "bg-info",
        "InTransit" => "bg-primary",
        "OutForDelivery" => "bg-warning text-dark",
        "Delivered" => "bg-success",
        "Cancelled" => "bg-danger",
        _ => "bg-secondary"
    };

    private static string FormatStatus(string status) => status switch
    {
        "PickedUp" => "Picked Up",
        "InTransit" => "In Transit",
        "OutForDelivery" => "Out for Delivery",
        _ => status
    };

    private static string GetProgressBarClass(string status) => status switch
    {
        "Cancelled" => "bg-danger",
        "Delivered" => "bg-success",
        _ => "bg-primary"
    };

    private static int GetProgressPercent(string status) => status switch
    {
        "Pending" => 10,
        "PickedUp" => 30,
        "InTransit" => 55,
        "OutForDelivery" => 80,
        "Delivered" => 100,
        "Cancelled" => 100,
        _ => 0
    };
}
